import React from 'react';

export default function ProjectSidebar() {
  return (
    <aside className="project-sidebar">
      <div className="project-title">Project</div>
      <ul>
        <li>Tracks</li>
        <li>Instruments</li>
        <li>Effects</li>
        <li>Samples</li>
      </ul>
    </aside>
  );
}
